// modules/tasks/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Handles task creation, retrieval, and management utilities.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'GET', path: '/tasks', auth: true },
    ],
    functions: ['getTasksForTeam'],
    types: ['Task', 'PaginationParams'],
  },

  sideEffects: [
    'reads from: tasks table',
    'reads from: teams table',
  ],

  invariants: [
    'Each task must belong to exactly one team',
    'A user can only see tasks for their assigned team',
  ],
});

// modules/tasks/lib/types.ts
import { User, Session } from '../auth/module.contract';

export interface Task {
  id: number;
  title: string;
  description: string;
  dueDate: Date;
  completed: boolean;
  teamId: number;
}

export interface PaginationParams {
  limit?: number;
  offset?: number;
}

// modules/tasks/lib/db.ts
import { query } from '../db';

export async function getTasksForTeam(teamId: number, paginationParams: PaginationParams): Promise<Task[]> {
  const { limit = 10, offset = 0 } = paginationParams;

  const result = await query<Task[]>(
    `
      SELECT * FROM tasks
      WHERE team_id = $1
      LIMIT $2 OFFSET $3
    `,
    [teamId, limit, offset]
  );

  return result.rows;
}

// modules/tasks/routes.ts
import { requireUser } from '../auth/lib/auth';
import { getTasksForTeam } from '../lib/db';
import { PaginationParams } from '../lib/types';

export async function listTasks(req: Request, res: Response) {
  const user = await requireUser(req);
  const paginationParams: PaginationParams = req.query as any;

  try {
    const tasks = await getTasksForTeam(user.teamId, paginationParams);
    return res.status(200).json(tasks);
  } catch (error) {
    return res.status(500).json({ error: 'Internal server error' });
  }
}

// modules/tasks/module.ts
import { defineModule } from 'aether';
import { listTasks } from './routes';

export default defineModule({
  name: 'tasks',
  routes: [
    {
      method: 'GET',
      path: '/tasks',
      handler: listTasks,
      auth: true,
    },
  ],
});

// modules/tasks/lib/queries.ts
import { query } from '../db';

export async function getTaskById(taskId: number): Promise<Task | null> {
  const result = await query<Task[]>(
    `
      SELECT * FROM tasks WHERE id = $1
    `,
    [taskId]
  );

  return result.rows[0] || null;
}

// modules/tasks/lib/auth.ts
import { requireUser } from '../auth/lib/auth';

export async function getTasksForTeam(teamId: number, paginationParams: PaginationParams): Promise<Task[]> {
  const { limit = 10, offset = 0 } = paginationParams;

  const result = await query<Task[]>(
    `
      SELECT * FROM tasks
      WHERE team_id = $1
      LIMIT $2 OFFSET $3
    `,
    [teamId, limit, offset]
  );

  return result.rows;
}

// modules/tasks/lib/db.ts
import { query } from '../db';

export async function getTasksForTeam(teamId: number, paginationParams: PaginationParams): Promise<Task[]> {
  const { limit = 10, offset = 0 } = paginationParams;

  const result = await query<Task[]>(
    `
      SELECT * FROM tasks
      WHERE team_id = $1
      LIMIT $2 OFFSET $3
    `,
